"use client"

import { useRef, useEffect, useCallback } from 'react';
import { createPortal } from 'react-dom';
import type { ReactNode } from 'react';

type Particle = {
  cx: number;
  y: number;
  vy: number;
  phase: number;
  amp: number;
  size: number;
  startTime: number;
};

type ClickFireTrailProps = {
  fillColor?: string;
  particleCount?: number;
  minRiseSpeed?: number;
  maxRiseSpeed?: number;
  minAmplitude?: number;
  maxAmplitude?: number;
  minSize?: number;
  maxSize?: number;
  shrinkRate?: number;
  duration?: number;
  children?: ReactNode;
};

export default function ClickFireTrail({
  fillColor = '#fff',
  particleCount = 15,
  minRiseSpeed = 2,
  maxRiseSpeed = 4,
  minAmplitude = 2,
  maxAmplitude = 6,
  minSize = 2,
  maxSize = 4,
  shrinkRate = 0.03,
  duration = 1500,
  children,
}: ClickFireTrailProps) {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const particlesRef = useRef<Particle[]>([]);
  const animIdRef = useRef<number | null>(null);

  // Sync canvas to full viewport
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const syncSize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    syncSize();
    window.addEventListener('resize', syncSize);
    return () => window.removeEventListener('resize', syncSize);
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const draw = (timestamp: number) => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      particlesRef.current = particlesRef.current.filter((p) => {
        const elapsed = timestamp - p.startTime;
        if (elapsed >= duration) return false;

        const progress = elapsed / duration;
        const alpha = Math.max(0, 1 - progress);

        p.y += p.vy;

        const xOffset = Math.sin(p.phase + p.y * 0.05) * p.amp;
        p.size = Math.max(0, p.size - shrinkRate);

        ctx.beginPath();
        ctx.arc(p.cx + xOffset, p.y, p.size, 0, Math.PI * 2);
        ctx.fillStyle = fillColor;
        ctx.globalAlpha = alpha;
        ctx.fill();
        ctx.globalAlpha = 1;

        return true;
      });

      animIdRef.current = requestAnimationFrame(draw);
    };

    animIdRef.current = requestAnimationFrame(draw);

    return () => {
      if (animIdRef.current !== null) {
        cancelAnimationFrame(animIdRef.current);
      }
    };
  }, [fillColor, duration, shrinkRate]);

  // clientX/Y maps directly to fixed canvas — no rect offset needed
  const handleClick = useCallback(
    (e: React.MouseEvent) => {
      const now = performance.now();

      const newParticles: Particle[] = Array.from(
        { length: particleCount },
        () => ({
          cx: e.clientX,
          y: e.clientY,
          vy: -(minRiseSpeed + Math.random() * (maxRiseSpeed - minRiseSpeed)),
          phase: Math.random() * Math.PI * 2,
          amp: minAmplitude + Math.random() * (maxAmplitude - minAmplitude),
          size: minSize + Math.random() * (maxSize - minSize),
          startTime: now,
        })
      );

      particlesRef.current.push(...newParticles);
    },
    [particleCount, minRiseSpeed, maxRiseSpeed, minAmplitude, maxAmplitude, minSize, maxSize]
  );

  return (
    <>
      <div style={{ display: 'contents' }} onClick={handleClick}>
        {children}
      </div>

      {typeof window !== 'undefined' &&
        createPortal(
          <canvas
            ref={canvasRef}
            style={{
              position: 'fixed',
              top: 0,
              left: 0,
              width: '100vw',
              height: '100vh',
              pointerEvents: 'none',
              zIndex: 9999,
            }}
          />,
          document.body
        )}
    </>
  );
}
